import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.Bb5YUzRP.js";var i=JSON.parse(`{"title":"开始进行深度编辑","description":"","frontmatter":{},"headers":[],"relativePath":"CodingHelp.md","filePath":"CodingHelp.md","lastUpdated":1784198763000}`),a={name:`CodingHelp.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="开始进行深度编辑" tabindex="-1">开始进行深度编辑 <a class="header-anchor" href="#开始进行深度编辑" aria-label="Permalink to “开始进行深度编辑”">​</a></h1><h2 id="配置git" tabindex="-1">配置Git <a class="header-anchor" href="#配置git" aria-label="Permalink to “配置Git”">​</a></h2><p>你需要用Git来管理你的网站，目前我最推荐的方法是用GitHub Desktop</p><p><a href="https://github.com/zetaloop/desktop/releases/" target="_blank" rel="noreferrer">Windows、MacOS请到这里下载GitHubDesktop</a></p><p><a href="https://github.com/shiftkey/desktop" target="_blank" rel="noreferrer">Linux版GitHubDesktop</a>，<a href="https://github.com/robotze/GithubDesktopZhTool" target="_blank" rel="noreferrer">LinuxGitHubDesktop汉化工具</a></p><p>把仓库克隆下来，然后用代码编辑器打开</p><h2 id="初始化项目" tabindex="-1">初始化项目 <a class="header-anchor" href="#初始化项目" aria-label="Permalink to “初始化项目”">​</a></h2><p>你需要在你的电脑上安装NodeJS和Yarn，那怎么安装呢？<s>好</s>问题：</p><h3 id="linux-初始化项目" tabindex="-1">Linux 初始化项目 <a class="header-anchor" href="#linux-初始化项目" aria-label="Permalink to “Linux 初始化项目”">​</a></h3><h4 id="首先安装-nodejs" tabindex="-1">首先安装 NodeJS <a class="header-anchor" href="#首先安装-nodejs" aria-label="Permalink to “首先安装 NodeJS”">​</a></h4><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-30" id="tab-31" checked><label data-title="Fedora" for="tab-31">Fedora</label><input type="radio" name="group-30" id="tab-32"><label data-title="Debian" for="tab-32">Debian</label></div><div class="blocks"><div class="language-sh active"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodejs</span></span></code></pre></div><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodejs</span></span></code></pre></div></div></div><p>装好NodeJS后，输入<code>node -v</code>，如果输出版本号就代表安装好了</p><p>如果没装好，自己找教程去</p><h4 id="然后安装-yarn" tabindex="-1">然后安装 Yarn <a class="header-anchor" href="#然后安装-yarn" aria-label="Permalink to “然后安装 Yarn”">​</a></h4><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> corepack</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">corepack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prepare</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yarn@stable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --activate</span></span></code></pre></div><p>然后，运行<code>yarn -v</code>，如果输出版本号为1开头，则装错了版本，如果是4开头，则装对了版本，但如果啥都不输出还报错了，那就是没装好</p><h4 id="windows-初始化项目" tabindex="-1">Windows 初始化项目 <a class="header-anchor" href="#windows-初始化项目" aria-label="Permalink to “Windows 初始化项目”">​</a></h4><p>打开管理员PowerShell，运行：</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install nodejs</span></span></code></pre></div><p>然后重新开启PowerShell，运行：</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">corepack enable</span></span></code></pre></div><p>重启PowerShell，运行：</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">yarn config set enableGlobalCache false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">corepack prepare yarn@stable </span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">activate</span></span></code></pre></div><p>然后，运行<code>yarn -v</code>，如果输出版本号为1开头，则装错了版本，如果是4开头，则装对了版本，但如果啥都不输出还报错了，那就是没装好</p><h2 id="预览与编译" tabindex="-1">预览与编译 <a class="header-anchor" href="#预览与编译" aria-label="Permalink to “预览与编译”">​</a></h2><h3 id="预览" tabindex="-1">预览 <a class="header-anchor" href="#预览" aria-label="Permalink to “预览”">​</a></h3><p>当你觉得改的差不多打算看看成果时，可以在终端运行：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span></code></pre></div><p>来预览网站，你甚至可以边改代码边预览，因为预览是实时渲染的</p><h3 id="编译-其实你可以不这样-我甚至不推荐这样" tabindex="-1">编译（其实你可以不这样，我甚至不推荐这样） <a class="header-anchor" href="#编译-其实你可以不这样-我甚至不推荐这样" aria-label="Permalink to “编译（其实你可以不这样，我甚至不推荐这样）”">​</a></h3><p>你觉得已经万事大吉了，打算更新网站时，仅需运行：</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre></div><p>这样dist就会更新为最新的</p><p>但我其实并不推荐你这样，因为该仓库配置了husky，会在提交时自动编译，而手动编译可能会和husky冲突，因此更推荐的做法是直接提交代码，让husky进行编译（如果husky炸了，请确保你<code>yarn install</code>过了，如果还不行那就手动编译吧）</p><h2 id="更新" tabindex="-1">更新 <a class="header-anchor" href="#更新" aria-label="Permalink to “更新”">​</a></h2><p>打开GitHubDesktop，随便填几下摘要，然后点击提交，husky自动完成编译，再点击推送，更新就会发送到GitHub上，GitHub的服务器会自动部署并更新网站，一般只需要等一分钟左右就能看到更新</p>`,36)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};